angular.module('starter').controller('FacebookembedHomeController',function(Dialog,Loader,$sce,Application,Facebookembed,$scope,$state,$stateParams){$scope.value_id=Facebookembed.value_id=$stateParams.value_id;$scope.payout={};$scope.facebook_url='';$scope.loadContent=function(){$scope.is_loading=!0;Loader.show();Facebookembed.findAll().success(function(data){$scope.page_title=data.page_title;$scope.payout=data;$scope.facebookPage='<iframe class="resp-iframe" src="https://www.facebook.com/plugins/page.php?href=https%3A%2F%2Fwww.facebook.com%2F'+$scope.payout.settings.page_name+'%2F&tabs='+$scope.payout.settings.tabs+'&width='+$scope.payout.settings.width+'&height='+$scope.payout.settings.height+'&small_header=false&adapt_container_width=true&hide_cover=false&show_facepile=true&appId" width="'+$scope.payout.settings.width+'" height="'+$scope.payout.settings.height+'" style="border:none;overflow:hidden" scrolling="no" frameborder="0" allowTransparency="true" allow="encrypted-media"></iframe>';Loader.hide();$scope.is_loading=!1}).error(function(error){Loader.hide();$scope.is_loading=!1;Dialog.alert($translate.instant("Error","facebookembed"),error.message,"OK",-1,"facebookembed")}).finally(function(){$scope.$broadcast('scroll.infiniteScrollComplete')})};$scope.loadContent()});angular.module('starter').factory('Facebookembed',function($pwaRequest){var factory={value_id:null};factory.setValueId=function(valueId){factory.value_id=valueId;return factory};factory.getValueId=function(){return factory.value_id};factory.findAll=function(){return $pwaRequest.post('facebookembed/mobile_view/findAll',{urlParams:{value_id:this.value_id},cache:!1,refresh:!0})};return factory});Features.insertCSS(".facebookembed .remove-border{border:0}.facebookembed .resp-container{position:relative;overflow:hidden}.facebookembed .resp-iframe{top:0;left:0;width:100%;border:0}","facebookembed")